import{_ as t,o as i,c as a,a2 as n}from"./chunks/framework.CHeM0PsO.js";const u=JSON.parse('{"title":"Native mobile app shell (Capacitor)","description":"","frontmatter":{"rfc":"0058","title":"Native mobile app shell (Capacitor)","status":"Draft","date":"July 2026","author":"kasunben","scope":"sovereign-mobile (separate repo), docs, packages/sdk","incorporated_into_plan":"Yes - epic tasks 20.1-20.9"},"headers":[],"relativePath":"rfcs/0058-native-mobile-app-shell.md","filePath":"rfcs/0058-native-mobile-app-shell.md"}'),s={name:"rfcs/0058-native-mobile-app-shell.md"};function o(r,e,l,d,c,h){return i(),a("div",null,[...e[0]||(e[0]=[n(`<h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>A minimal native mobile shell app (<code>sovereign-mobile</code>) built with Capacitor. One app is published for iOS and Android. On first launch, the user enters the URL of their self-hosted Sovereign instance; the app persists that URL and loads the instance in a WebView. Multiple instances are supported.</p><p>The native app does not duplicate Sovereign&#39;s runtime, auth, shell, or plugin system. The user&#39;s instance remains the source of truth. The mobile app is a thin native wrapper that provides distribution through the App Store and Play Store, native permissions, WebView hosting, and a path for richer device APIs via <code>sdk.device.*</code>.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>Sovereign v1 ships as an installable PWA. That covers the install-from-browser use case, but it does not cover users who expect a native app from the App Store or Play Store, nor does it provide the best path for native-only capabilities such as APNs/FCM push, biometric auth, native photo picking, haptics, and background location.</p><p>The product model is self-hosted and plugin-first, so the native app must not become a second platform. It should load the user&#39;s own instance unchanged. That keeps plugins portable across browser, PWA, and native mobile, and lets the platform continue to evolve in the web runtime instead of forking behavior into Swift and Kotlin clients.</p><h2 id="current-state" tabindex="-1">Current state <a class="header-anchor" href="#current-state" aria-label="Permalink to &quot;Current state&quot;">​</a></h2><ul><li>The SRS already defines native mobile as a post-v1 plan: <code>docs/sovereign-proposal-plan-srs.md:680</code>.</li><li>The SRS decision log records three related decisions: <code>docs/sovereign-proposal-plan-srs.md:1164</code>, <code>docs/sovereign-proposal-plan-srs.md:1165</code>, and <code>docs/sovereign-proposal-plan-srs.md:1166</code>.</li><li><code>docs/architecture.md:216</code> summarizes native mobile as a Capacitor shell plus <code>sdk.device.*</code>, designed but out of v1 scope.</li><li>RFC 0013 treats mobile web hardening as the baseline inherited by the future Capacitor shell: <code>docs/rfcs/0013-mobile-responsiveness-pwa.md:38</code>.</li><li>RFC 0038 mirrors this client model for desktop: <code>docs/rfcs/0038-desktop-app-shell.md:18</code>.</li></ul><h2 id="proposed-design" tabindex="-1">Proposed design <a class="header-anchor" href="#proposed-design" aria-label="Permalink to &quot;Proposed design&quot;">​</a></h2><h3 id="repository" tabindex="-1">Repository <a class="header-anchor" href="#repository" aria-label="Permalink to &quot;Repository&quot;">​</a></h3><p><code>sovereign-mobile</code> is a separate repository under the Sovereign project, not a package inside this monorepo. It is developed and versioned independently of the platform, matching the documented desktop-shell pattern.</p><p>The repository owns only native shell concerns:</p><ul><li>Capacitor app scaffold.</li><li>iOS and Android project files.</li><li>First-launch onboarding UI for instance URL entry.</li><li>Persistent instance list storage.</li><li>WebView loading and navigation policy.</li><li>Native permission declarations.</li><li>App Store and Play Store release metadata.</li><li>Native bridge implementation needed by <code>sdk.device.*</code>.</li></ul><h3 id="technology-capacitor" tabindex="-1">Technology: Capacitor <a class="header-anchor" href="#technology-capacitor" aria-label="Permalink to &quot;Technology: Capacitor&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Concern</th><th>Choice</th><th>Why</th></tr></thead><tbody><tr><td>Shell framework</td><td>Capacitor</td><td>TypeScript-first shell for iOS and Android</td></tr><tr><td>iOS WebView</td><td>WKWebView</td><td>Standard iOS WebView; same engine targeted by mobile web</td></tr><tr><td>Android WebView</td><td>Android System WebView</td><td>Standard Android runtime WebView</td></tr><tr><td>Shell logic</td><td>TypeScript</td><td>Consistent with the rest of Sovereign</td></tr><tr><td>Native extensions</td><td>Capacitor plugins</td><td>Standard bridge for native-only capabilities</td></tr><tr><td>Native languages</td><td>Swift/Kotlin only as needed</td><td>Avoids platform-specific app logic by default</td></tr><tr><td>Release channels</td><td>App Store and Play Store</td><td>Expected distribution path for native mobile users</td></tr></tbody></table><h3 id="first-launch-onboarding-flow" tabindex="-1">First-launch onboarding flow <a class="header-anchor" href="#first-launch-onboarding-flow" aria-label="Permalink to &quot;First-launch onboarding flow&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App opens</span></span>
<span class="line"><span>  |- No instance URL stored?</span></span>
<span class="line"><span>  |    |- Show onboarding screen</span></span>
<span class="line"><span>  |    |- User enters instance URL</span></span>
<span class="line"><span>  |    |- Validate URL against the instance</span></span>
<span class="line"><span>  |    |    |- Valid: persist URL, then load it in the WebView</span></span>
<span class="line"><span>  |    |    \`- Invalid: show inline error and let the user retry</span></span>
<span class="line"><span>  \`- URL stored?</span></span>
<span class="line"><span>       \`- Load stored URL directly in the WebView</span></span></code></pre></div><p>The validation endpoint should be stable, unauthenticated, and already available to deployments before the mobile shell ships. If no dedicated mobile capability endpoint exists when implementation starts, use the same health/capability check chosen for the desktop shell to avoid divergent client logic.</p><h3 id="multiple-instances" tabindex="-1">Multiple instances <a class="header-anchor" href="#multiple-instances" aria-label="Permalink to &quot;Multiple instances&quot;">​</a></h3><p>The shell stores an ordered list of instance URLs. Users can add, remove, and switch between instances such as personal and work deployments. The active instance is loaded in the WebView; switching instances replaces the WebView URL instead of creating a separate native account model.</p><p>Session state remains owned by the instance in its WebView storage. The mobile shell may expose instance management UI, but it does not own Sovereign users, roles, auth sessions, or plugin permissions.</p><h3 id="webview-and-navigation-policy" tabindex="-1">WebView and navigation policy <a class="header-anchor" href="#webview-and-navigation-policy" aria-label="Permalink to &quot;WebView and navigation policy&quot;">​</a></h3><p>The shell loads only user-configured Sovereign instances in the primary WebView. External links should open in the platform browser or an approved in-app browser surface instead of silently navigating the shell away from the configured instance.</p><p>The runtime remains responsible for:</p><ul><li>Auth and session handling.</li><li>Plugin routing and shell layout.</li><li>CSP and security headers.</li><li>PWA/mobile responsive behavior inherited by the WebView.</li><li>Server-rendered UI and plugin composition.</li></ul><p>The native shell is responsible for:</p><ul><li>Instance URL onboarding and persistence.</li><li>WebView lifecycle.</li><li>Store-facing app metadata.</li><li>Native permission declarations.</li><li>Native bridge calls exposed through the SDK.</li></ul><h3 id="device-api-strategy" tabindex="-1">Device API strategy <a class="header-anchor" href="#device-api-strategy" aria-label="Permalink to &quot;Device API strategy&quot;">​</a></h3><p>The mobile shell follows the three-tier strategy already recorded in the SRS.</p><table tabindex="0"><thead><tr><th>Tier</th><th>Technology</th><th>Examples</th><th>Browser support</th></tr></thead><tbody><tr><td>Web APIs</td><td>Standard browser APIs available in WebView</td><td>GPS, camera/mic, accelerometer, Web Push where supported</td><td>Yes</td></tr><tr><td>Capacitor plugins</td><td>JS bridge to native code</td><td>Native photo picker, APNs/FCM push, Face ID/fingerprint, background location, haptics</td><td>No, native shell only</td></tr><tr><td>SDK abstraction</td><td><code>sdk.device.*</code> detects environment and routes accordingly</td><td><code>sdk.device.getLocation()</code>, <code>sdk.device.capturePhoto()</code>, future device capability calls</td><td>Yes, with browser fallback</td></tr></tbody></table><p>Plugin developers call <code>sdk.device.*</code> only. They do not import Capacitor plugins or branch directly on native shell internals. The SDK implementation detects the environment and selects the browser, PWA, or native-mobile tier. Plugins should continue to run unchanged outside the native shell.</p><h3 id="capability-roadmap" tabindex="-1">Capability roadmap <a class="header-anchor" href="#capability-roadmap" aria-label="Permalink to &quot;Capability roadmap&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Capability</th><th>Initial shell</th><th>Later native capability</th></tr></thead><tbody><tr><td>Instance URL onboarding</td><td>Yes</td><td>-</td></tr><tr><td>Persistent instance storage</td><td>Yes</td><td>-</td></tr><tr><td>WebView shell</td><td>Yes</td><td>-</td></tr><tr><td>Multiple instance switcher</td><td>Yes</td><td>-</td></tr><tr><td>iOS App Store distribution</td><td>Yes</td><td>-</td></tr><tr><td>Android Play Store distribution</td><td>Yes</td><td>-</td></tr><tr><td>Native photo picker</td><td>No</td><td>Capacitor camera/photo plugin</td></tr><tr><td>APNs/FCM push notifications</td><td>No</td><td>Capacitor push notifications plugin</td></tr><tr><td>Face ID / fingerprint</td><td>No</td><td>Capacitor biometric auth plugin</td></tr><tr><td>Haptics</td><td>No</td><td>Capacitor haptics plugin</td></tr><tr><td>Background location or background work</td><td>No</td><td>Separate capability RFC/task</td></tr></tbody></table><p>The initial shell should stay small. Native capability work lands only when a plugin-facing SDK contract exists and the permission/privacy behavior is documented.</p><h3 id="store-and-privacy-constraints" tabindex="-1">Store and privacy constraints <a class="header-anchor" href="#store-and-privacy-constraints" aria-label="Permalink to &quot;Store and privacy constraints&quot;">​</a></h3><p>The published app must be clear that it connects to a user-provided Sovereign instance. Store metadata should avoid implying that Sovereign hosts the user&#39;s data by default.</p><p>Before store submission, implementation tasks must define:</p><ul><li>App privacy labels / data safety declarations.</li><li>Required native permission strings and justifications.</li><li>Minimum supported iOS and Android versions.</li><li>App identifiers, signing, and release ownership.</li><li>Whether instance URL entry allows any HTTPS URL or only validated Sovereign instances.</li></ul><p>The shell should not introduce telemetry by default. Any future crash reporting or analytics must follow Sovereign&#39;s privacy-first posture and be opt-in or operator-controlled.</p><h2 id="ui-flows" tabindex="-1">UI flows <a class="header-anchor" href="#ui-flows" aria-label="Permalink to &quot;UI flows&quot;">​</a></h2><h3 id="add-first-instance" tabindex="-1">Add first instance <a class="header-anchor" href="#add-first-instance" aria-label="Permalink to &quot;Add first instance&quot;">​</a></h3><ol><li>User installs and opens the mobile app.</li><li>Shell shows a first-run screen asking for the Sovereign instance URL.</li><li>User enters an HTTPS URL.</li><li>Shell validates that the URL is reachable and identifies as a compatible Sovereign instance.</li><li>Shell stores the instance URL and loads it in the WebView.</li><li>User signs in through the instance&#39;s normal auth flow.</li></ol><h3 id="switch-instance" tabindex="-1">Switch instance <a class="header-anchor" href="#switch-instance" aria-label="Permalink to &quot;Switch instance&quot;">​</a></h3><ol><li>User opens the native shell&#39;s instance switcher.</li><li>Shell lists saved instances.</li><li>User selects another instance.</li><li>Shell replaces the WebView URL with the selected instance.</li><li>That instance&#39;s own auth/session state determines whether the user is already signed in.</li></ol><h3 id="use-a-native-backed-device-capability" tabindex="-1">Use a native-backed device capability <a class="header-anchor" href="#use-a-native-backed-device-capability" aria-label="Permalink to &quot;Use a native-backed device capability&quot;">​</a></h3><ol><li>A plugin calls <code>sdk.device.*</code>.</li><li>The SDK detects that it is running in the native mobile shell.</li><li>If a native implementation exists, the SDK calls the Capacitor bridge.</li><li>The OS prompts for permission when required.</li><li>The SDK returns a normalized result or a normalized permission/error state to the plugin.</li><li>The same plugin code keeps working in browser/PWA contexts through Web API fallback or documented unsupported states.</li></ol><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li>PWA only: already the v1 plan and remains supported, but it does not satisfy store distribution or all native capability needs.</li><li>Separate native apps per instance: rejected because self-hosters would need to build and distribute their own app. That conflicts with the goal of one reusable Sovereign mobile shell.</li><li>React Native: better for fully native UI, but Sovereign&#39;s UI and plugin system already live in the web runtime. Rebuilding platform UI in React Native would create a second client.</li><li>Hotwire Native with Swift and Kotlin: offers a more native-feeling wrapper, but it requires platform-specific implementation and custom bridges for each device capability. Capacitor better matches the TypeScript stack and SDK abstraction.</li><li>Plugins calling Capacitor directly: rejected because it breaks portability and couples plugin code to one shell. <code>sdk.device.*</code> remains the boundary.</li></ul><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol><li>Which endpoint should the shell use for first-launch instance validation and compatibility metadata?</li><li>Minimum supported iOS and Android versions.</li><li>Whether push notifications ship with the initial shell or as the first follow-up native capability.</li><li>How the instance switcher is exposed without fighting the web shell&#39;s own navigation and account UI.</li><li>Exact package shape for the SDK&#39;s native bridge adapter.</li></ol><h2 id="adoption-path" tabindex="-1">Adoption path <a class="header-anchor" href="#adoption-path" aria-label="Permalink to &quot;Adoption path&quot;">​</a></h2><ol><li>RFC merges and becomes the canonical native mobile design reference.</li><li>Epic tasks 20.1-20.9 track the mobile shell, validation endpoint, SDK bridge, store release setup, and native capability phases.</li><li>Create the <code>sovereign-mobile</code> repository with Capacitor, onboarding, WebView loading, persistent instance storage, and iOS/Android builds.</li><li>Add SDK native-mobile environment routing for <code>sdk.device.*</code>. Public SDK surface changes require semver according to the actual API delta.</li><li>Add native capability tasks one at a time, each with permission, privacy, SDK, docs, and store-review impact called out.</li></ol><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>0.1</td><td>July 2026</td><td>Initial draft</td></tr></tbody></table>`,54)])])}const b=t(s,[["render",o]]);export{u as __pageData,b as default};
